  /* throttle busy clients (slowloris) */
  fio_suspend(uuid);
  p->stop |= 4;
  FIO_LOG_DEBUG("(HTTP/1,1) throttling client at %.*s",
                (int)fio_peer_addr(uuid).len, fio_peer_addr(uuid).data);
