  /* resume slow clients from suspension */
  http1pr_s *p = (http1pr_s *)protocol;
  if ((p->stop & 4)) {
    p->stop ^= 4;
    fio_force_event(uuid, FIO_EVENT_ON_DATA);
  }
  (void)protocol;
}

